          '1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 1 1 3\nauthor Diego Alvarez\nauthor-mail <diego.alvarez@example.com>\nauthor-time 1777727400\nauthor-tz +0200\ncommitter Diego Alvarez\ncommitter-mail <diego.alvarez@example.com>\ncommitter-time 1777727400\ncommitter-tz +0200\nsummary feat(frequency): add serialize_header for compact code-length table encoding\nprevious ee63ac520307b5bb894fbc53be67143a642b2e9d frequency.py\nfilename frequency.py\n\timport struct\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 2 2\n\t\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 3 3\n\t\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 1 4 7\nauthor Maya Chen\nauthor-mail <maya.chen@example.com>\nauthor-time 1777277640\nauthor-tz +0200\ncommitter Maya Chen\ncommitter-mail <maya.chen@example.com>\ncommitter-time 1777277640\ncommitter-tz +0200\nsummary feat(frequency): add count_frequencies with sorted symbol-count output\nboundary\nfilename frequency.py\n\tdef count_frequencies(path: str) -> list[tuple[int, int]]:\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 2 5\n\t    counts: dict[int, int] = {}\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 3 6\n\t    with open(path, "rb") as f:\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 4 7\n\t        for chunk in iter(lambda: f.read(65536), b""):\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 5 8\n\t            for byte in chunk:\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 6 9\n\t                counts[byte] = counts.get(byte, 0) + 1\n9cf1cafd5c0e5473b6ab151f2c08b445dcb7448c 7 10\n\t    return sorted(counts.items(), key=lambda item: (item[1], item[0]))\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 11 11 6\n\t\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 12 12\n\t\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 13 13\n\tdef serialize_header(original_byte_length: int, lengths: dict[int, int]) -> bytes:\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 14 14\n\t    """Serialize code-length table as an 8-byte length prefix + 256-byte length array."""\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 15 15\n\t    length_array = bytes(lengths.get(sym, 0) for sym in range(256))\n1f2c9930e71aa71c86cfa16d37060e10a2a14ab3 16 16\n\t    return struct.pack(">Q", original_byte_length) + length_array\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 17 17 13\nauthor Priya Shah\nauthor-mail <priya.shah@example.com>\nauthor-time 1777908000\nauthor-tz +0200\ncommitter Priya Shah\ncommitter-mail <priya.shah@example.com>\ncommitter-time 1777908000\ncommitter-tz +0200\nsummary feat(frequency): add parse_header to deserialize the compact code-length header\nprevious e484650c91f8c8599fad69cbe4dfd9ba8c6c1286 frequency.py\nfilename frequency.py\n\t\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 18 18\n\tdef parse_header(fh) -> tuple[int, dict[int, int]]:\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 19 19\n\t    """Read the 264-byte header written by serialize_header from *fh*.\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 20 20\n\t\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 21 21\n\t    Returns (original_byte_length, lengths) where lengths maps each symbol\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 22 22\n\t    with a non-zero code length to its bit length.\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 23 23\n\t    """\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 24 24\n\t    raw = fh.read(8 + 256)\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 25 25\n\t    if len(raw) < 8 + 256:\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 26 26\n\t        raise ValueError("truncated header")\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 27 27\n\t    (original_byte_length,) = struct.unpack(">Q", raw[:8])\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 28 28\n\t    lengths = {sym: raw[8 + sym] for sym in range(256) if raw[8 + sym] != 0}\nf7dc9481f03b85a1fab712689a2251ebb8ba5b0f 29 29\n\t    return original_byte_length, lengths\n',
